// src/Welcome.js
import React from 'react';
import './welcome.css'; // Optional: For styles
import logo from 'D:\CDRD\Account_Section\project\project\frontend\public\crd logo.png'; // Adjust path as needed

const Welcome = () => {
  return (
    <div>
      <header className="header">
        <div className="logo-container">
          <h1>CENTER FOR DEFENCE RESEARCH AND DEVELOPMENT</h1>
        </div>
        <div className="login1">
          <a href="/login" className="login-button">Login</a>
        </div>
        <img src={logo} alt="Logo" className="logo" />
      </header>
      <main>
        <section>
          <h2 className="header2">Quotation Tracking System</h2>
        </section>
      </main>
    </div>
  );
};

export default Welcome;
